import{_ as a,c as n,o as e,a as l}from"./chunks/plugin-vue_export-helper.dqZ0aIgD.js";const b=JSON.parse('{"title":"Installation","description":"Install Lynq on a Kubernetes cluster using Helm (recommended), Kustomize, or from source. Covers cert-manager setup, verification, and upgrades.","frontmatter":{"description":"Install Lynq on a Kubernetes cluster using Helm (recommended), Kustomize, or from source. Covers cert-manager setup, verification, and upgrades."},"headers":[],"relativePath":"installation.md","filePath":"installation.md","lastUpdated":1779353865000}'),r={name:"installation.md"};function o(p,s,t,c,i,d){return e(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>This guide covers deploying Lynq to a production or staging cluster. For a local Minikube setup, see <a href="./quickstart.html">Quick Start</a>.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Minimum version</th><th>Notes</th></tr></thead><tbody><tr><td>Kubernetes</td><td>v1.28+</td><td>v1.31+ for latest test coverage</td></tr><tr><td>kubectl</td><td>Matches cluster</td><td></td></tr><tr><td>cert-manager</td><td><strong>v1.13.0+</strong></td><td><strong>Required.</strong> Manages webhook TLS automatically.</td></tr></tbody></table><h3 id="install-cert-manager" tabindex="-1">Install cert-manager <a class="header-anchor" href="#install-cert-manager" aria-label="Permalink to &quot;Install cert-manager&quot;">​</a></h3><p>cert-manager must be running before Lynq is deployed. It provisions and renews the TLS certificates that Lynq&#39;s admission webhooks require.</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> apply</span><span style="color:#79B8FF;"> -f</span><span style="color:#9ECBFF;"> https://github.com/cert-manager/cert-manager/releases/download/v1.13.0/cert-manager.yaml</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Wait for all three cert-manager components to be ready</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> wait</span><span style="color:#79B8FF;"> --for=condition=Available</span><span style="color:#79B8FF;"> --timeout=300s</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> cert-manager</span><span style="color:#79B8FF;"> \\</span></span>
<span class="line"><span style="color:#9ECBFF;">  deployment/cert-manager</span><span style="color:#79B8FF;"> \\</span></span>
<span class="line"><span style="color:#9ECBFF;">  deployment/cert-manager-webhook</span><span style="color:#79B8FF;"> \\</span></span>
<span class="line"><span style="color:#9ECBFF;">  deployment/cert-manager-cainjector</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>If cert-manager is already installed (v1.13.0+), skip this step.</p><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><h3 id="helm-recommended" tabindex="-1">Helm (Recommended) <a class="header-anchor" href="#helm-recommended" aria-label="Permalink to &quot;Helm (Recommended)&quot;">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">helm</span><span style="color:#9ECBFF;"> repo</span><span style="color:#9ECBFF;"> add</span><span style="color:#9ECBFF;"> lynq</span><span style="color:#9ECBFF;"> https://k8s-lynq.github.io/lynq</span></span>
<span class="line"><span style="color:#B392F0;">helm</span><span style="color:#9ECBFF;"> repo</span><span style="color:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="color:#B392F0;">helm</span><span style="color:#9ECBFF;"> install</span><span style="color:#9ECBFF;"> lynq</span><span style="color:#9ECBFF;"> lynq/lynq</span><span style="color:#79B8FF;"> \\</span></span>
<span class="line"><span style="color:#79B8FF;">  --namespace</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#79B8FF;"> \\</span></span>
<span class="line"><span style="color:#79B8FF;">  --create-namespace</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>See the <a href="https://github.com/k8s-lynq/lynq/blob/main/chart/README.md" target="_blank" rel="noreferrer">Helm Chart README</a> for all values.</p><h3 id="kustomize" tabindex="-1">Kustomize <a class="header-anchor" href="#kustomize" aria-label="Permalink to &quot;Kustomize&quot;">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> apply</span><span style="color:#79B8FF;"> -k</span><span style="color:#9ECBFF;"> https://github.com/k8s-lynq/lynq/config/default</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="from-source" tabindex="-1">From Source <a class="header-anchor" href="#from-source" aria-label="Permalink to &quot;From Source&quot;">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">git</span><span style="color:#9ECBFF;"> clone</span><span style="color:#9ECBFF;"> https://github.com/k8s-lynq/lynq.git</span></span>
<span class="line"><span style="color:#79B8FF;">cd</span><span style="color:#9ECBFF;"> lynq</span></span>
<span class="line"><span style="color:#B392F0;">make</span><span style="color:#9ECBFF;"> install</span><span style="color:#6A737D;">                                    # install CRDs</span></span>
<span class="line"><span style="color:#B392F0;">make</span><span style="color:#9ECBFF;"> deploy</span><span style="color:#9ECBFF;"> IMG=ghcr.io/k8s-lynq/lynq:latest</span><span style="color:#6A737D;">  # deploy operator</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h2><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> deployment</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> lynq-controller-manager</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> crd</span><span style="color:#F97583;"> |</span><span style="color:#B392F0;"> grep</span><span style="color:#9ECBFF;"> operator.lynq.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Expected CRDs:</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span>lynqhubs.operator.lynq.sh</span></span>
<span class="line"><span>lynqforms.operator.lynq.sh</span></span>
<span class="line"><span>lynqnodes.operator.lynq.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>If the operator pod is crashing, check webhook TLS first:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> describe</span><span style="color:#9ECBFF;"> pod</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#79B8FF;"> -l</span><span style="color:#9ECBFF;"> control-plane=controller-manager</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="resource-limits" tabindex="-1">Resource Limits <a class="header-anchor" href="#resource-limits" aria-label="Permalink to &quot;Resource Limits&quot;">​</a></h3><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># config/manager/manager.yaml (shipped defaults)</span></span>
<span class="line"><span style="color:#85E89D;">resources</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  limits</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    cpu</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">500m</span></span>
<span class="line"><span style="color:#85E89D;">    memory</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">128Mi</span></span>
<span class="line"><span style="color:#85E89D;">  requests</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    cpu</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">10m</span></span>
<span class="line"><span style="color:#85E89D;">    memory</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">64Mi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>Increase memory before scaling beyond a few hundred LynqNodes. See <a href="./resource-sizing.html">Resource Sizing</a> for benchmarks and a CPU/memory model.</p><h3 id="concurrency" tabindex="-1">Concurrency <a class="header-anchor" href="#concurrency" aria-label="Permalink to &quot;Concurrency&quot;">​</a></h3><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">args</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--hub-concurrency=3</span><span style="color:#6A737D;">    # concurrent hub syncs (default: 3)</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--form-concurrency=5</span><span style="color:#6A737D;">   # concurrent form reconciliations (default: 5)</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--node-concurrency=10</span><span style="color:#6A737D;">  # concurrent node reconciliations (default: 10)</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">--leader-elect</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="multi-architecture" tabindex="-1">Multi-Architecture <a class="header-anchor" href="#multi-architecture" aria-label="Permalink to &quot;Multi-Architecture&quot;">​</a></h3><p>Pre-built images support <code>linux/amd64</code> and <code>linux/arm64</code>. Docker automatically selects the right image for your nodes.</p><h2 id="upgrade" tabindex="-1">Upgrade <a class="header-anchor" href="#upgrade" aria-label="Permalink to &quot;Upgrade&quot;">​</a></h2><p>Always upgrade CRDs before upgrading the operator:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># 1. Upgrade CRDs (preserves existing data)</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> apply</span><span style="color:#79B8FF;"> -f</span><span style="color:#9ECBFF;"> config/crd/bases/</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># 2. Upgrade operator</span></span>
<span class="line"><span style="color:#B392F0;">helm</span><span style="color:#9ECBFF;"> upgrade</span><span style="color:#9ECBFF;"> lynq</span><span style="color:#9ECBFF;"> lynq/lynq</span><span style="color:#79B8FF;"> --namespace</span><span style="color:#9ECBFF;"> lynq-system</span></span>
<span class="line"><span style="color:#6A737D;"># or:</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> set</span><span style="color:#9ECBFF;"> image</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#79B8FF;"> \\</span></span>
<span class="line"><span style="color:#9ECBFF;">  deployment/lynq-controller-manager</span><span style="color:#79B8FF;"> \\</span></span>
<span class="line"><span style="color:#9ECBFF;">  manager=ghcr.io/k8s-lynq/lynq:v1.1.20</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>To roll back:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> rollout</span><span style="color:#9ECBFF;"> undo</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> deployment/lynq-controller-manager</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="uninstall" tabindex="-1">Uninstall <a class="header-anchor" href="#uninstall" aria-label="Permalink to &quot;Uninstall&quot;">​</a></h2><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Remove operator (keeps CRDs and node data)</span></span>
<span class="line"><span style="color:#B392F0;">helm</span><span style="color:#9ECBFF;"> uninstall</span><span style="color:#9ECBFF;"> lynq</span><span style="color:#79B8FF;"> --namespace</span><span style="color:#9ECBFF;"> lynq-system</span></span>
<span class="line"><span style="color:#6A737D;"># or: kubectl delete -k config/default</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Remove CRDs — this deletes all LynqHub, LynqForm, and LynqNode resources</span></span>
<span class="line"><span style="color:#B392F0;">make</span><span style="color:#9ECBFF;"> uninstall</span></span>
<span class="line"><span style="color:#6A737D;"># or: kubectl delete crd lynqhubs.operator.lynq.sh lynqforms.operator.lynq.sh lynqnodes.operator.lynq.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">CRD deletion is destructive</p><p>Deleting the CRDs deletes all custom resources. Back up your LynqHub and LynqForm manifests before running <code>make uninstall</code>.</p></div><h2 id="troubleshooting-installation" tabindex="-1">Troubleshooting Installation <a class="header-anchor" href="#troubleshooting-installation" aria-label="Permalink to &quot;Troubleshooting Installation&quot;">​</a></h2><p><strong><code>no such file or directory: tls.crt</code></strong> — cert-manager is not ready or not installed:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> pods</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> cert-manager</span></span>
<span class="line"><span style="color:#6A737D;"># If missing: install cert-manager (see Prerequisites above)</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> rollout</span><span style="color:#9ECBFF;"> restart</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> deployment/lynq-controller-manager</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong><code>AlreadyExists</code> on CRDs</strong> — normal during upgrades. The apply is idempotent.</p><p><strong><code>ImagePullBackOff</code></strong> — cluster can&#39;t reach <code>ghcr.io</code>. Check network policies or configure an image pull secret.</p><p><strong><code>Forbidden: cannot create resource</code></strong> — RBAC not applied:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> apply</span><span style="color:#79B8FF;"> -f</span><span style="color:#9ECBFF;"> config/rbac/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./quickstart.html">Quick Start</a> — local Minikube setup with automated scripts</li><li><a href="./configuration.html">Configuration</a> — all operator flags and settings</li><li><a href="./security.html">Security</a> — RBAC, credential management, and audit logging</li><li><a href="./monitoring.html">Monitoring</a> — Prometheus metrics and alerting</li></ul>`,47)])])}const y=a(r,[["render",o]]);export{b as __pageData,y as default};
